update client_balance
set balance = balance - #{fee,jdbcType=BIGINT},
    updated = now()

        , update_id = #{updateId,jdbcType=BIGINT}

where client_id = #{clientId,jdbcType=BIGINT}
  and is_delete = 0
  and balance - #{fee,jdbcType=BIGINT}  >=  #{amountLimit,jdbcType=BIGINT}

update client_balance
set balance = balance + #{amount,jdbcType=BIGINT},
    updated = now()

        , update_id = #{updateId,jdbcType=BIGINT}

where client_id = #{clientId,jdbcType=BIGINT}
  and is_delete = 0

update client_balance
set balance = balance + #{delta,jdbcType=BIGINT},
    updated = now()

        , update_id = #{updateId,jdbcType=BIGINT}

where client_id = #{clientId,jdbcType=BIGINT}
  and is_delete = 0

    and balance + #{delta,jdbcType=BIGINT}  >=  #{amountLimit,jdbcType=BIGINT}
